THOUGHT: I will fix the malformed if (Known.One.isOne()) logic by inserting proper braces and the poison-protection guard, rebuild opt, and rerun the reproducer to confirm the transformation no longer incorrectly drops the select to expose a samesign icmp. I will also attempt submit-patch again even if not found.

```bash
sed -i '4073,4081c\    if (Known.One.isOne()) {
      if (auto *ICmp = dyn_cast<ICmpInst>(TrueVal))
        if (ICmp->isSameSign()) {
          /* Avoid folding select to a samesign icmp; may expose poison when condition is false (PR: miscompile reproducer). */
          return nullptr;
        }
      return replaceInstUsesWith(SI, TrueVal);
    }
    if (Known.Zero.isOne())
      return replaceInstUsesWith(SI, FalseVal);' llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp && \
nl -ba llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp | sed -n '4068,4085p' && \
ninja -C /llvm-autofix/build/llvm-build/112356 opt >/dev/null 2>&1 || echo "Build failed" && \
echo "Reproducer before opt:" && cat /tmp/test.ll && echo "---- opt output ----" && /llvm-autofix/build/llvm-build/112356/bin/opt /tmp/test.ll -passes=instcombine -S || true && \
submit-patch || echo "submit-patch command not found"
```

